sql:
SELECT name, updated_date 
FROM management_packs 
WHERE management_pack_id = (SELECT MAX(management_pack_id) FROM management_packs);

SELECT management_pack_id, COUNT(*) as workflow_count
FROM workflows
GROUP BY management_pack_id;

SELECT name, version, released_date
FROM management_packs
ORDER BY released_date DESC;

SELECT name, released_date
FROM management_packs
ORDER BY released_date ASC;

external_knowledge:
; Management packs are collections of monitoring rules and tasks for system administration; 
; The 'latest update date' refers to the most recent date on which a management pack was updated; 
; The query aims to provide a concise overview of the management packs and their update history.

sql:
SELECT name, version, MAX(updated_date) AS latest_update
FROM management_packs
GROUP BY management_pack_id;
